import path from "node:path";
import dotenv from "dotenv";

dotenv.config({ path: path.resolve(process.cwd(), "config.env") });
dotenv.config();

import cors from "cors";
import express from "express";
import ticketsRouter from "./routes/tickets.js";
import { seedTickets } from "./store.js";

const PORT = Number(process.env.PORT) || 5070;
const FRONTEND_URL = process.env.FRONTEND_URL || "http://localhost:5175";

const app = express();
app.use(
  cors({
    origin: FRONTEND_URL,
    credentials: true,
  }),
);
app.use(express.json());

app.get("/health", (_req, res) => {
  res.status(200).json({ ok: true });
});

app.use("/api", ticketsRouter);

app.use(
  (
    err: unknown,
    _req: express.Request,
    res: express.Response,
    _next: express.NextFunction,
  ) => {
    console.error(err);
    res.status(500).json({ error: "INTERNAL", message: "Server error." });
  },
);

seedTickets();

if (process.env.NODE_ENV !== "test") {
  app.listen(PORT, () => {
    console.log(`TicketFlow API http://localhost:${PORT}`);
  });
}

export default app;

import type { CreateTicketBody, Ticket, TicketPriority } from "./types.js";

let nextId = 1;
const tickets = new Map<string, Ticket>();

function makeTicket(
  partial: Omit<Ticket, "id" | "createdAt"> & { createdAt?: string },
): Ticket {
  const id = String(nextId++);
  const ticket: Ticket = {
    id,
    createdAt: partial.createdAt ?? new Date().toISOString(),
    title: partial.title,
    description: partial.description,
    priority: partial.priority,
    status: partial.status,
  };
  tickets.set(id, ticket);
  return ticket;
}

export function resetStore(): void {
  tickets.clear();
  nextId = 1;
}

export function seedTickets(): Ticket[] {
  resetStore();
  const now = Date.now();
  return [
    makeTicket({
      title: "Login page returns 500",
      description: "Users cannot sign in after the latest deploy.",
      priority: "high",
      status: "open",
      createdAt: new Date(now - 5 * 60_000).toISOString(),
    }),
    makeTicket({
      title: "Export CSV missing headers",
      description: "Downloaded CSV has data rows but no column names.",
      priority: "medium",
      status: "in_progress",
      createdAt: new Date(now - 4 * 60_000).toISOString(),
    }),
    makeTicket({
      title: "Dark mode toggle misaligned",
      description: "Settings toggle overlaps the sidebar on mobile.",
      priority: "low",
      status: "open",
      createdAt: new Date(now - 3 * 60_000).toISOString(),
    }),
    makeTicket({
      title: "Webhook retries exhausted",
      description: "Partner integration stopped receiving events.",
      priority: "high",
      status: "resolved",
      createdAt: new Date(now - 2 * 60_000).toISOString(),
    }),
    makeTicket({
      title: "Password reset email delayed",
      description: "Reset emails arrive 30+ minutes late.",
      priority: "medium",
      status: "open",
      createdAt: new Date(now - 1 * 60_000).toISOString(),
    }),
  ];
}

export function listTickets(): Ticket[] {
  return Array.from(tickets.values());
}

export function getTicket(id: string): Ticket | undefined {
  return tickets.get(id);
}

export function createTicket(body: CreateTicketBody): Ticket {
  return makeTicket({
    title: body.title.trim(),
    description: body.description.trim(),
    priority: body.priority,
    status: "open",
  });
}

export function updateTicket(
  id: string,
  patch: Partial<Pick<Ticket, "title" | "description" | "priority" | "status">>,
): Ticket | undefined {
  const existing = tickets.get(id);
  if (!existing) return undefined;

  const updated: Ticket = {
    ...existing,
    ...patch,
    id: existing.id,
    createdAt: existing.createdAt,
  };
  tickets.set(id, updated);
  return updated;
}

export function priorityRank(priority: TicketPriority): number {
  return { low: 1, medium: 2, high: 3 }[priority];
}

export type TicketPriority = "low" | "medium" | "high";
export type TicketStatus = "open" | "in_progress" | "resolved";

export interface Ticket {
  id: string;
  title: string;
  description: string;
  priority: TicketPriority;
  status: TicketStatus;
  createdAt: string;
}

export interface CreateTicketBody {
  title: string;
  description: string;
  priority: TicketPriority;
}

export interface UpdateTicketBody {
  title?: string;
  description?: string;
  priority?: TicketPriority;
  status?: TicketStatus;
}

export const VALID_PRIORITIES: TicketPriority[] = ["low", "medium", "high"];
export const VALID_STATUSES: TicketStatus[] = ["open", "in_progress", "resolved"];

/** Allowed status transitions per product requirements. */
export const ALLOWED_STATUS_TRANSITIONS: Record<TicketStatus, TicketStatus[]> = {
  open: ["in_progress"],
  in_progress: ["resolved", "open"],
  resolved: ["open"],
};

import { Router } from "express";
import {
  createTicket,
  getTicket,
  listTickets,
  priorityRank,
  updateTicket,
} from "../store.js";
import type { Ticket, TicketPriority, TicketStatus } from "../types.js";
import { VALID_PRIORITIES, VALID_STATUSES } from "../types.js";

const router = Router();

function filterByPriority(tickets: Ticket[], priority: TicketPriority): Ticket[] {
  // BUG 2: uses >= on string priority labels instead of exact match.
  // String comparison makes "low" >= "high" true (alphabetical), so filtering
  // by high incorrectly includes low-priority tickets.
  return tickets.filter((ticket) => ticket.priority >= priority);
}

function sortTickets(tickets: Ticket[]): Ticket[] {
  // BUG 3: README requires oldest-first; this sorts newest-first.
  return [...tickets].sort(
    (a, b) => new Date(b.createdAt).getTime() - new Date(a.createdAt).getTime(),
  );
}

router.get("/tickets", (req, res) => {
  let results = listTickets();

  const priority = req.query.priority as TicketPriority | undefined;
  if (priority) {
    if (!VALID_PRIORITIES.includes(priority)) {
      return res.status(400).json({
        error: "INVALID_PRIORITY",
        message: `priority must be one of: ${VALID_PRIORITIES.join(", ")}`,
      });
    }
    results = filterByPriority(results, priority);
  }

  const status = req.query.status as TicketStatus | undefined;
  if (status) {
    if (!VALID_STATUSES.includes(status)) {
      return res.status(400).json({
        error: "INVALID_STATUS",
        message: `status must be one of: ${VALID_STATUSES.join(", ")}`,
      });
    }
    results = results.filter((ticket) => ticket.status === status);
  }

  res.json({ tickets: sortTickets(results) });
});

router.post("/tickets", (req, res) => {
  const { title, description, priority } = req.body ?? {};

  if (!title || typeof title !== "string" || !title.trim()) {
    return res.status(400).json({ error: "INVALID_TITLE", message: "title is required" });
  }
  if (!description || typeof description !== "string") {
    return res
      .status(400)
      .json({ error: "INVALID_DESCRIPTION", message: "description is required" });
  }
  if (!priority || !VALID_PRIORITIES.includes(priority)) {
    return res.status(400).json({
      error: "INVALID_PRIORITY",
      message: `priority must be one of: ${VALID_PRIORITIES.join(", ")}`,
    });
  }

  const ticket = createTicket({ title, description, priority });
  res.status(201).json({ ticket });
});

router.patch("/tickets/:id", (req, res) => {
  const existing = getTicket(req.params.id);
  if (!existing) {
    return res.status(404).json({ error: "NOT_FOUND", message: "Ticket not found" });
  }

  const { title, description, priority, status } = req.body ?? {};
  const patch: Partial<Pick<Ticket, "title" | "description" | "priority" | "status">> = {};

  if (title !== undefined) {
    if (typeof title !== "string" || !title.trim()) {
      return res.status(400).json({ error: "INVALID_TITLE", message: "title must be a string" });
    }
    patch.title = title.trim();
  }

  if (description !== undefined) {
    if (typeof description !== "string") {
      return res
        .status(400)
        .json({ error: "INVALID_DESCRIPTION", message: "description must be a string" });
    }
    patch.description = description;
  }

  if (priority !== undefined) {
    if (!VALID_PRIORITIES.includes(priority)) {
      return res.status(400).json({
        error: "INVALID_PRIORITY",
        message: `priority must be one of: ${VALID_PRIORITIES.join(", ")}`,
      });
    }
    patch.priority = priority;
  }

  if (status !== undefined) {
    if (!VALID_STATUSES.includes(status)) {
      return res.status(400).json({
        error: "INVALID_STATUS",
        message: `status must be one of: ${VALID_STATUSES.join(", ")}`,
      });
    }

    // BUG 1: accepts any valid status string without enforcing the state machine.
    // README: tickets must go through in_progress before resolved.
    patch.status = status;
  }

  const ticket = updateTicket(req.params.id, patch);
  res.json({ ticket });
});

// Feature 2 (not implemented in starter): stats dashboard endpoint.
// Candidates should add GET /api/stats returning counts grouped by status.

export { filterByPriority, sortTickets, priorityRank };
export default router;

import assert from "node:assert/strict";
import { afterEach, beforeEach, describe, it } from "node:test";
import request from "supertest";
import app from "../src/server.js";
import { createTicket, getTicket, resetStore, seedTickets } from "../src/store.js";

describe("TicketFlow API", () => {
  beforeEach(() => {
    resetStore();
  });

  afterEach(() => {
    resetStore();
  });

  describe("Bug 1 — status state machine", () => {
    it("rejects open → resolved without passing through in_progress", async () => {
      const ticket = createTicket({
        title: "Broken checkout",
        description: "Payment form fails on submit",
        priority: "high",
      });

      const response = await request(app)
        .patch(`/api/tickets/${ticket.id}`)
        .send({ status: "resolved" });

      assert.equal(response.status, 400, response.body?.message ?? "expected 400");
      assert.equal(response.body.error, "INVALID_STATUS_TRANSITION");
      assert.equal(getTicket(ticket.id)?.status, "open");
    });
  });

  describe("Bug 2 — priority filter", () => {
    it('returns only high-priority tickets when ?priority=high', async () => {
      createTicket({
        title: "High severity outage",
        description: "Production is down",
        priority: "high",
      });
      createTicket({
        title: "Minor copy tweak",
        description: "Button label typo",
        priority: "low",
      });

      const response = await request(app).get("/api/tickets?priority=high");

      assert.equal(response.status, 200);
      const priorities = response.body.tickets.map(
        (ticket: { priority: string }) => ticket.priority,
      );
      assert.ok(
        priorities.every((priority: string) => priority === "high"),
        `expected only high-priority tickets, got: ${priorities.join(", ")}`,
      );
    });
  });

  describe("Bug 3 — chronological sort order", () => {
    it("lists tickets oldest-first by createdAt", async () => {
      seedTickets();

      const response = await request(app).get("/api/tickets");

      assert.equal(response.status, 200);
      const titles = response.body.tickets.map((ticket: { title: string }) => ticket.title);
      assert.equal(
        titles[0],
        "Login page returns 500",
        `expected oldest ticket first, got order: ${titles.join(" → ")}`,
      );
      assert.equal(titles[titles.length - 1], "Password reset email delayed");
    });
  });

  describe("Baseline behavior", () => {
    it("creates and fetches tickets", async () => {
      seedTickets();
      const response = await request(app).get("/api/tickets");
      assert.equal(response.status, 200);
      assert.ok(response.body.tickets.length >= 5);
    });
  });
});

{
  "name": "ticketflow-client",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "scripts": {
    "dev": "vite",
    "build": "vite build",
    "preview": "vite preview"
  },
  "dependencies": {
    "react": "^18.3.1",
    "react-dom": "^18.3.1"
  },
  "devDependencies": {
    "@vitejs/plugin-react": "^4.3.4",
    "vite": "^6.0.3"
  }
}

import { defineConfig } from "vite";
import react from "@vitejs/plugin-react";

export default defineConfig({
  plugins: [react()],
  server: {
    port: 5175,
  },
});

import { StrictMode } from "react";
import { createRoot } from "react-dom/client";
import App from "./App.jsx";
import "./index.css";

createRoot(document.getElementById("root")).render(
  <StrictMode>
    <App />
  </StrictMode>,
);

import { useCallback, useEffect, useState } from "react";
import { createTicket, fetchTickets, updateTicket } from "./api.js";

const PRIORITIES = ["low", "medium", "high"];
const STATUSES = ["open", "in_progress", "resolved"];

const EMPTY_FORM = {
  title: "",
  description: "",
  priority: "medium",
};

export default function App() {
  const [tickets, setTickets] = useState([]);
  const [priorityFilter, setPriorityFilter] = useState("");
  const [statusFilter, setStatusFilter] = useState("");
  const [form, setForm] = useState(EMPTY_FORM);
  const [loading, setLoading] = useState(true);
  const [submitting, setSubmitting] = useState(false);
  const [error, setError] = useState("");

  const loadTickets = useCallback(async () => {
    setLoading(true);
    setError("");
    try {
      const data = await fetchTickets({
        priority: priorityFilter || undefined,
        status: statusFilter || undefined,
      });
      setTickets(data.tickets);
    } catch (err) {
      setError(err.message || "Failed to load tickets");
    } finally {
      setLoading(false);
    }
  }, [priorityFilter, statusFilter]);

  useEffect(() => {
    loadTickets();
  }, [loadTickets]);

  async function handleCreate(event) {
    event.preventDefault();
    setSubmitting(true);
    setError("");
    try {
      await createTicket(form);
      setForm(EMPTY_FORM);
      await loadTickets();
    } catch (err) {
      setError(err.message || "Failed to create ticket");
    } finally {
      setSubmitting(false);
    }
  }

  async function handleStatusChange(ticketId, status) {
    setError("");
    try {
      await updateTicket(ticketId, { status });
      await loadTickets();
    } catch (err) {
      setError(err.message || "Failed to update ticket");
    }
  }

  return (
    <div className="app">
      <header className="header">
        <h1>TicketFlow</h1>
        <p>Support ticket triage for the demo assessment starter repo.</p>
      </header>

      {error ? <div className="error">{error}</div> : null}

      <section className="panel">
        <h2>Filters</h2>
        <div className="filters">
          <label>
            Priority
            <select
              value={priorityFilter}
              onChange={(event) => setPriorityFilter(event.target.value)}
            >
              <option value="">All priorities</option>
              {PRIORITIES.map((priority) => (
                <option key={priority} value={priority}>
                  {priority}
                </option>
              ))}
            </select>
          </label>
          <label>
            Status
            <select
              value={statusFilter}
              onChange={(event) => setStatusFilter(event.target.value)}
            >
              <option value="">All statuses</option>
              {STATUSES.map((status) => (
                <option key={status} value={status}>
                  {status.replace("_", " ")}
                </option>
              ))}
            </select>
          </label>
        </div>
        <p className="muted" style={{ marginTop: "0.75rem" }}>
          Feature 1 (search) is not implemented yet — add a search box that queries the API.
        </p>
      </section>

      <section className="panel">
        <h2>Create ticket</h2>
        <form className="form-grid" onSubmit={handleCreate}>
          <input
            required
            placeholder="Title"
            value={form.title}
            onChange={(event) => setForm({ ...form, title: event.target.value })}
          />
          <textarea
            required
            placeholder="Description"
            value={form.description}
            onChange={(event) => setForm({ ...form, description: event.target.value })}
          />
          <select
            value={form.priority}
            onChange={(event) => setForm({ ...form, priority: event.target.value })}
          >
            {PRIORITIES.map((priority) => (
              <option key={priority} value={priority}>
                {priority}
              </option>
            ))}
          </select>
          <button className="primary-button" type="submit" disabled={submitting}>
            {submitting ? "Creating..." : "Create ticket"}
          </button>
        </form>
      </section>

      <section className="panel">
        <h2>Tickets</h2>
        {loading ? (
          <p className="muted">Loading tickets...</p>
        ) : tickets.length === 0 ? (
          <div className="empty">No tickets match the current filters.</div>
        ) : (
          <div className="ticket-list">
            {tickets.map((ticket) => (
              <article key={ticket.id} className="ticket-card">
                <h3>{ticket.title}</h3>
                <div className="ticket-meta">
                  <span className={`badge priority-${ticket.priority}`}>{ticket.priority}</span>
                  <span className={`badge status-${ticket.status}`}>
                    {ticket.status.replace("_", " ")}
                  </span>
                  <span className="muted">
                    Created {new Date(ticket.createdAt).toLocaleString()}
                  </span>
                </div>
                <p className="ticket-description">{ticket.description}</p>
                <div className="ticket-actions">
                  <select
                    value={ticket.status}
                    onChange={(event) => handleStatusChange(ticket.id, event.target.value)}
                  >
                    {STATUSES.map((status) => (
                      <option key={status} value={status}>
                        {status.replace("_", " ")}
                      </option>
                    ))}
                  </select>
                  <button
                    type="button"
                    className="secondary-button"
                    onClick={() => loadTickets()}
                  >
                    Refresh
                  </button>
                </div>
              </article>
            ))}
          </div>
        )}
      </section>

      <section className="panel">
        <h2>Stats</h2>
        <p className="muted">
          Feature 2 (stats dashboard) is not implemented yet — add{" "}
          <code>GET /api/stats</code> and a summary bar here.
        </p>
      </section>
    </div>
  );
}

const API_BASE = import.meta.env.VITE_API_URL || "http://localhost:5070";

async function request(path, options = {}) {
  const response = await fetch(`${API_BASE}${path}`, {
    headers: {
      "Content-Type": "application/json",
      ...(options.headers || {}),
    },
    ...options,
  });

  const data = await response.json().catch(() => ({}));
  if (!response.ok) {
    const message = data.message || data.error || response.statusText;
    throw new Error(message);
  }
  return data;
}

export function fetchTickets({ priority, status } = {}) {
  const params = new URLSearchParams();
  if (priority) params.set("priority", priority);
  if (status) params.set("status", status);
  const query = params.toString();
  return request(`/api/tickets${query ? `?${query}` : ""}`);
}

export function createTicket(body) {
  return request("/api/tickets", {
    method: "POST",
    body: JSON.stringify(body),
  });
}

export function updateTicket(id, body) {
  return request(`/api/tickets/${id}`, {
    method: "PATCH",
    body: JSON.stringify(body),
  });
}

